int dis[3005][3005];
var se = set<array<int, 3>>();
struct node {
	int id, last, d;
};
void solve(int CASE)
{
	int n, m, k; cin >> n >> m >> k;
	fa(i, 0, n)fa(j, 0, n)dis[i][j] = INF;
	var g = vector<vector<int>>(n + 1);
	fa(i, 1, m) {
		int u, v; cin >> u >> v;
		g[u].pb(v), g[v].pb(u);
	}
	fa(i, 1, k) {
		var a = array<int, 3>();
		fa(j, 0, 2)cin >> a[j];
		se.insert(a);
	}
	var Q = queue<node>();
	Q.push({ 1,0,dis[1][0] = 0 });
	while (Q.size()) {
		var[now, last, d] = Q.front();
		Q.pop();
		if (d > dis[now][last])continue;
		for (int to : g[now]) {
			if (se.count({ last, now, to }))continue;
			if (dis[to][now] > dis[now][last] + 1) {
				dis[to][now] = dis[now][last] + 1;
				Q.push({ to, now, dis[to][now] });
			}
		}
	}
	int mn = INF, mnlast = 0;
	fa(last, 1, n - 1) {
		if (mn > dis[n][last]) {
			mn = dis[n][last];
			mnlast = last;
		}
	}

	if (mn >= INF) {
		cout << -1 << endl;
		return;
	}

	cout << mn << endl;
	var ans = vector<int>();
	ans.pb(n);

  	// 回溯
	int now = n;
	while (mnlast) {
		ans.pb(mnlast);
		fb(i, n, 0) {
			if (dis[mnlast][i] == dis[now][mnlast] - 1) {
				now = mnlast;
				mnlast = i;
				break;
			}
		}
	}
	reverse(all(ans));
	cout << ans << endl;
	return;
}
